package controllers.amateur;

import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.layout.HBox;

import java.util.function.Consumer;

public class MiniAudioPlayerController {

    @FXML
    private HBox playerBar;

    @FXML
    private Button togglePlayButton;

    private Consumer<String> navigationHandler;
    private boolean playing;

    @FXML
    public void initialize() {
        playerBar.setVisible(false);
        playerBar.setManaged(false);
    }

    public void setNavigationHandler(Consumer<String> navigationHandler) {
        this.navigationHandler = navigationHandler;
    }

    public void setVisibleForRoute(String route) {
        boolean isMusicPage = "musique".equals(route);
        playerBar.setVisible(!isMusicPage);
        playerBar.setManaged(!isMusicPage);
    }

    @FXML
    private void onTogglePlay() {
        playing = !playing;
        togglePlayButton.setText(playing ? "||" : ">");
    }

    @FXML
    private void onPrevTrack() {
        // Placeholder for queue previous action.
    }

    @FXML
    private void onNextTrack() {
        // Placeholder for queue next action.
    }

    @FXML
    private void onOpenMusic() {
        if (navigationHandler != null) {
            navigationHandler.accept("musique");
        }
    }
}

package controllers.artist;

import entities.Evenement;
import javafx.fxml.FXML;
import javafx.scene.control.Label;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;

import java.io.ByteArrayInputStream;
import java.time.format.DateTimeFormatter;

public class EvenementArtisteCardController {

    public interface CardActionHandler {
        void onEdit(Evenement evenement);

        void onDelete(Evenement evenement);
    }

    private static final DateTimeFormatter DATE_FORMATTER = DateTimeFormatter.ofPattern("dd/MM/yyyy HH:mm");

    @FXML
    private ImageView coverImageView;

    @FXML
    private Label titreLabel;

    @FXML
    private Label dateTypeLabel;

    @FXML
    private Label statusMetaLabel;

    @FXML
    private Label descriptionLabel;

    private Evenement evenement;
    private CardActionHandler actionHandler;

    public void setData(Evenement evenement, CardActionHandler actionHandler) {
        this.evenement = evenement;
        this.actionHandler = actionHandler;

        titreLabel.setText(textOrDefault(evenement.getTitre(), "Evenement sans titre"));
        dateTypeLabel.setText(formatMainMeta(evenement));
        statusMetaLabel.setText(formatSecondaryMeta(evenement));
        descriptionLabel.setText(textOrDefault(evenement.getDescription(), "Aucune description"));
        applyImage(evenement.getImageCouverture());
    }

    @FXML
    private void onEditClick() {
        if (actionHandler != null && evenement != null) {
            actionHandler.onEdit(evenement);
        }
    }

    @FXML
    private void onDeleteClick() {
        if (actionHandler != null && evenement != null) {
            actionHandler.onDelete(evenement);
        }
    }

    private String formatMainMeta(Evenement evenement) {
        String date = evenement.getDateDebut() == null ? "Date non definie" : DATE_FORMATTER.format(evenement.getDateDebut());
        String type = textOrDefault(evenement.getType(), "Type non precise");
        return date + "  |  " + type;
    }

    private String formatSecondaryMeta(Evenement evenement) {
        String statut = textOrDefault(evenement.getStatut(), "A venir");
        String capacite = evenement.getCapaciteMax() == null ? "-" : String.valueOf(evenement.getCapaciteMax());
        return "Statut: " + statut + "  |  Places: " + capacite;
    }

    private void applyImage(byte[] imageBytes) {
        if (imageBytes == null || imageBytes.length == 0) {
            coverImageView.setImage(null);
            return;
        }

        try {
            Image image = new Image(new ByteArrayInputStream(imageBytes));
            if (image.isError()) {
                coverImageView.setImage(null);
                return;
            }
            coverImageView.setImage(image);
        } catch (Exception ignored) {
            coverImageView.setImage(null);
        }
    }

    private String textOrDefault(String value, String fallback) {
        return value == null || value.isBlank() ? fallback : value;
    }
}

package controllers.artist;

import entities.Evenement;
import entities.Galerie;
import javafx.fxml.FXML;
import javafx.scene.control.ComboBox;
import javafx.scene.control.Label;
import javafx.scene.control.TextArea;
import javafx.scene.control.TextField;
import javafx.stage.FileChooser;
import javafx.stage.Stage;
import services.GalerieService;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.sql.SQLDataException;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.time.format.DateTimeParseException;
import java.util.ArrayList;
import java.util.List;

public class EvenementArtisteFormController {

    private static final DateTimeFormatter DATE_TIME_FORMATTER = DateTimeFormatter.ofPattern("dd/MM/yyyy HH:mm");

    @FXML
    private Label formTitleLabel;

    @FXML
    private TextField titreField;

    @FXML
    private ComboBox<String> typeComboBox;

    @FXML
    private TextField dateDebutField;

    @FXML
    private TextField dateFinField;

    @FXML
    private TextField capaciteField;

    @FXML
    private TextField prixField;

    @FXML
    private ComboBox<GalerieOption> galerieComboBox;

    @FXML
    private Label imageFileLabel;

    @FXML
    private TextArea descriptionArea;

    @FXML
    private Label validationErrorLabel;

    private final GalerieService galerieService = new GalerieService();
    private final List<GalerieOption> galerieOptions = new ArrayList<>();

    private Stage dialogStage;
    private Evenement originalEvenement;
    private Evenement resultEvenement;
    private byte[] selectedImageBytes;

    @FXML
    public void initialize() {
        typeComboBox.getItems().addAll("Exposition", "Concert", "Spectacle", "Conference", "Atelier", "Autre");
        typeComboBox.setValue("Exposition");

        clearValidationError();
        wireFieldListeners();
        loadGaleries();
    }

    public void setDialogStage(Stage dialogStage) {
        this.dialogStage = dialogStage;
    }

    public void setEvenement(Evenement evenement) {
        this.originalEvenement = evenement;
        clearValidationError();

        if (evenement == null) {
            formTitleLabel.setText("Ajouter un evenement");
            titreField.clear();
            typeComboBox.setValue("Exposition");
            dateDebutField.clear();
            dateFinField.clear();
            capaciteField.clear();
            prixField.clear();
            if (!galerieOptions.isEmpty()) {
                galerieComboBox.setValue(galerieOptions.get(0));
            }
            descriptionArea.clear();
            imageFileLabel.setText("Aucun fichier choisi");
            selectedImageBytes = null;
            return;
        }

        formTitleLabel.setText("Modifier un evenement");
        titreField.setText(evenement.getTitre());
        typeComboBox.setValue(evenement.getType() == null || evenement.getType().isBlank() ? "Exposition" : evenement.getType());
        dateDebutField.setText(formatDateTime(evenement.getDateDebut()));
        dateFinField.setText(formatDateTime(evenement.getDateFin()));
        capaciteField.setText(evenement.getCapaciteMax() == null ? "" : String.valueOf(evenement.getCapaciteMax()));
        prixField.setText(evenement.getPrixTicket() == null ? "" : String.valueOf(evenement.getPrixTicket()));
        descriptionArea.setText(evenement.getDescription());
        imageFileLabel.setText(evenement.getImageCouverture() == null || evenement.getImageCouverture().length == 0
                ? "Aucun fichier choisi"
                : "Image existante" );
        selectedImageBytes = evenement.getImageCouverture();

        GalerieOption selected = findGalerieOption(evenement.getGalerieId());
        if (selected != null) {
            galerieComboBox.setValue(selected);
        }
    }

    public Evenement getResultEvenement() {
        return resultEvenement;
    }

    @FXML
    private void onChooseImageClick() {
        FileChooser fileChooser = new FileChooser();
        fileChooser.setTitle("Choisir image de couverture");
        fileChooser.getExtensionFilters().addAll(
                new FileChooser.ExtensionFilter("Images", "*.png", "*.jpg", "*.jpeg", "*.webp")
        );

        File selectedFile = fileChooser.showOpenDialog(dialogStage);
        if (selectedFile == null) {
            return;
        }

        try {
            selectedImageBytes = Files.readAllBytes(selectedFile.toPath());
            imageFileLabel.setText(selectedFile.getName());
            clearValidationError();
        } catch (IOException e) {
            showValidationError("Impossible de lire le fichier image choisi.");
        }
    }

    @FXML
    private void onSaveClick() {
        clearValidationError();

        String titre = safeTrim(titreField.getText());
        String type = safeTrim(typeComboBox.getValue());
        String dateDebutText = safeTrim(dateDebutField.getText());
        String dateFinText = safeTrim(dateFinField.getText());
        String capaciteText = safeTrim(capaciteField.getText());
        String prixText = safeTrim(prixField.getText());
        String description = safeTrim(descriptionArea.getText());
        GalerieOption selectedGalerie = galerieComboBox.getValue();

        if (titre.isEmpty() || type.isEmpty() || dateDebutText.isEmpty() || dateFinText.isEmpty() || selectedGalerie == null) {
            showValidationError("Veuillez remplir les champs obligatoires.");
            return;
        }

        LocalDateTime dateDebut = parseDateTime(dateDebutText, "Date debut invalide. Format attendu: dd/MM/yyyy HH:mm");
        if (dateDebut == null) {
            return;
        }

        LocalDateTime dateFin = parseDateTime(dateFinText, "Date fin invalide. Format attendu: dd/MM/yyyy HH:mm");
        if (dateFin == null) {
            return;
        }

        if (dateFin.isBefore(dateDebut)) {
            showValidationError("La date fin doit etre apres la date debut.");
            return;
        }

        Integer capacite = null;
        if (!capaciteText.isEmpty()) {
            try {
                capacite = Integer.parseInt(capaciteText);
                if (capacite <= 0) {
                    showValidationError("La capacite doit etre superieure a 0.");
                    return;
                }
            } catch (NumberFormatException e) {
                showValidationError("La capacite max doit etre un nombre entier.");
                return;
            }
        }

        Double prixTicket = null;
        if (!prixText.isEmpty()) {
            try {
                prixTicket = Double.parseDouble(prixText.replace(',', '.'));
                if (prixTicket < 0) {
                    showValidationError("Le prix ticket doit etre positif.");
                    return;
                }
            } catch (NumberFormatException e) {
                showValidationError("Le prix ticket doit etre un nombre valide.");
                return;
            }
        }

        Evenement evenement = new Evenement();
        if (originalEvenement != null) {
            evenement.setId(originalEvenement.getId());
            evenement.setArtisteId(originalEvenement.getArtisteId());
        }

        evenement.setTitre(titre);
        evenement.setType(type);
        evenement.setDateDebut(dateDebut);
        evenement.setDateFin(dateFin);
        evenement.setDateCreation(originalEvenement != null && originalEvenement.getDateCreation() != null
                ? originalEvenement.getDateCreation()
                : LocalDate.now());
        evenement.setDescription(description);
        evenement.setCapaciteMax(capacite);
        evenement.setPrixTicket(prixTicket);
        evenement.setGalerieId(selectedGalerie.id());
        evenement.setImageCouverture(selectedImageBytes);
        evenement.setStatut(computeStatut(dateDebut, dateFin));

        resultEvenement = evenement;
        closeDialog();
    }

    @FXML
    private void onCancelClick() {
        resultEvenement = null;
        closeDialog();
    }

    private void loadGaleries() {
        try {
            galerieOptions.clear();
            for (Galerie galerie : galerieService.getAll()) {
                galerieOptions.add(new GalerieOption(galerie.getId(), galerie.getNom()));
            }
            galerieComboBox.getItems().setAll(galerieOptions);
            if (!galerieOptions.isEmpty()) {
                galerieComboBox.setValue(galerieOptions.get(0));
            }
        } catch (SQLDataException e) {
            showValidationError("Impossible de charger la liste des galeries.");
        }
    }

    private GalerieOption findGalerieOption(Integer galerieId) {
        if (galerieId == null) {
            return null;
        }
        for (GalerieOption option : galerieOptions) {
            if (galerieId.equals(option.id())) {
                return option;
            }
        }
        return null;
    }

    private void wireFieldListeners() {
        titreField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        dateDebutField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        dateFinField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        capaciteField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        prixField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        descriptionArea.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        typeComboBox.valueProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        galerieComboBox.valueProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
    }

    private LocalDateTime parseDateTime(String text, String errorMessage) {
        try {
            return LocalDateTime.parse(text, DATE_TIME_FORMATTER);
        } catch (DateTimeParseException e) {
            showValidationError(errorMessage);
            return null;
        }
    }

    private String computeStatut(LocalDateTime debut, LocalDateTime fin) {
        LocalDateTime now = LocalDateTime.now();
        if (now.isBefore(debut)) {
            return "A venir";
        }
        if (now.isAfter(fin)) {
            return "Termine";
        }
        return "En cours";
    }

    private String formatDateTime(LocalDateTime dateTime) {
        return dateTime == null ? "" : DATE_TIME_FORMATTER.format(dateTime);
    }

    private String safeTrim(String value) {
        return value == null ? "" : value.trim();
    }

    private void closeDialog() {
        if (dialogStage != null) {
            dialogStage.close();
        }
    }

    private void showValidationError(String message) {
        validationErrorLabel.setText(message);
        validationErrorLabel.setVisible(true);
        validationErrorLabel.setManaged(true);
    }

    private void clearValidationError() {
        if (validationErrorLabel == null) {
            return;
        }
        validationErrorLabel.setText("");
        validationErrorLabel.setVisible(false);
        validationErrorLabel.setManaged(false);
    }

    private record GalerieOption(Integer id, String nom) {
        @Override
        public String toString() {
            return nom == null || nom.isBlank() ? "Galerie #" + id : nom;
        }
    }
}

package controllers.artist;

public class EvenementsArtisteController {
}

package controllers.artist;

import controllers.artist.EvenementArtisteCardController;
import controllers.artist.EvenementArtisteFormController;
import entities.Evenement;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Node;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.scene.control.Alert;
import javafx.scene.control.Button;
import javafx.scene.control.ButtonBar;
import javafx.scene.control.ButtonType;
import javafx.scene.control.ComboBox;
import javafx.scene.control.Label;
import javafx.scene.control.TextField;
import javafx.scene.layout.VBox;
import javafx.stage.Modality;
import javafx.stage.Stage;
import services.EvenementService;

import java.io.IOException;
import java.net.URL;
import java.sql.SQLDataException;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Objects;
import java.util.Optional;
import java.util.stream.Collectors;

public class EvenementsArtisteController {

	// TODO: replace this with authenticated session user id when auth flow is connected.
	private static final int CURRENT_ARTIST_ID = 1;

	@FXML
	private TextField rechercheField;

	@FXML
	private ComboBox<String> triComboBox;

	@FXML
	private VBox eventsListContainer;

	@FXML
	private Label emptyStateLabel;

	@FXML
	private Button addEvenementButton;

	private final EvenementService evenementService = new EvenementService();
	private final List<Evenement> allEvenements = new ArrayList<>();

	@FXML
	public void initialize() {
		triComboBox.getItems().addAll(
				"Date (plus recente)",
				"Date (plus ancienne)",
				"Titre (A-Z)",
				"Titre (Z-A)",
				"Type (A-Z)"
		);
		triComboBox.setValue("Date (plus recente)");

		rechercheField.textProperty().addListener((observable, oldValue, newValue) -> applySearchAndSort());
		triComboBox.valueProperty().addListener((observable, oldValue, newValue) -> applySearchAndSort());

		refreshEvenements();
	}

	@FXML
	private void onAddEvenementClick() {
		Optional<Evenement> evenementResult = openFormDialog(null);
		if (evenementResult.isEmpty()) {
			return;
		}

		try {
			evenementService.addForArtiste(evenementResult.get(), CURRENT_ARTIST_ID);
			refreshEvenements();
		} catch (SQLDataException e) {
			showError("Ajout impossible", e.getMessage());
		}
	}

	private void refreshEvenements() {
		try {
			allEvenements.clear();
			allEvenements.addAll(evenementService.getByArtisteId(CURRENT_ARTIST_ID));
			applySearchAndSort();
		} catch (SQLDataException e) {
			showError("Chargement impossible", e.getMessage());
		}
	}

	private void applySearchAndSort() {
		String search = rechercheField.getText() == null ? "" : rechercheField.getText().trim().toLowerCase();

		List<Evenement> filtered = allEvenements.stream()
				.filter(event -> matchesSearch(event, search))
				.sorted(buildComparator(triComboBox.getValue()))
				.collect(Collectors.toList());

		renderCards(filtered);
	}

	private boolean matchesSearch(Evenement event, String search) {
		if (search.isEmpty()) {
			return true;
		}

		return contains(event.getTitre(), search)
				|| contains(event.getType(), search)
				|| contains(event.getDescription(), search)
				|| contains(event.getStatut(), search);
	}

	private Comparator<Evenement> buildComparator(String selectedSort) {
		if (selectedSort == null) {
			return Comparator.comparing(EvenementsArtisteController::safeDateTime, Comparator.reverseOrder());
		}

		return switch (selectedSort) {
			case "Date (plus ancienne)" -> Comparator.comparing(EvenementsArtisteController::safeDateTime);
			case "Titre (A-Z)" -> Comparator.comparing(event -> safe(event.getTitre()));
			case "Titre (Z-A)" -> Comparator.comparing((Evenement event) -> safe(event.getTitre())).reversed();
			case "Type (A-Z)" -> Comparator.comparing(event -> safe(event.getType()));
			case "Date (plus recente)" -> Comparator.comparing(EvenementsArtisteController::safeDateTime, Comparator.reverseOrder());
			default -> Comparator.comparing(EvenementsArtisteController::safeDateTime, Comparator.reverseOrder());
		};
	}

	private void renderCards(List<Evenement> events) {
		eventsListContainer.getChildren().clear();

		for (Evenement event : events) {
			try {
				FXMLLoader loader = new FXMLLoader(Objects.requireNonNull(getClass().getResource("/views/artist/components/evenement-artiste-card.fxml")));
				Parent card = loader.load();
				EvenementArtisteCardController cardController = loader.getController();
				cardController.setData(event, new EvenementArtisteCardController.CardActionHandler() {
					@Override
					public void onEdit(Evenement evenement) {
						handleEdit(evenement);
					}

					@Override
					public void onDelete(Evenement evenement) {
						handleDelete(evenement);
					}
				});
				eventsListContainer.getChildren().add(card);
			} catch (IOException e) {
				showError("Affichage impossible", "Erreur pendant le rendu d'un evenement.");
				return;
			}
		}

		boolean empty = events.isEmpty();
		emptyStateLabel.setVisible(empty);
		emptyStateLabel.setManaged(empty);
	}

	private void handleEdit(Evenement evenementToEdit) {
		Optional<Evenement> evenementResult = openFormDialog(evenementToEdit);
		if (evenementResult.isEmpty()) {
			return;
		}

		try {
			evenementService.updateForArtiste(evenementResult.get(), CURRENT_ARTIST_ID);
			refreshEvenements();
		} catch (SQLDataException e) {
			showError("Modification impossible", e.getMessage());
		}
	}

	private void handleDelete(Evenement evenementToDelete) {
		ButtonType deleteButton = new ButtonType("Supprimer", ButtonBar.ButtonData.OK_DONE);
		ButtonType cancelButton = new ButtonType("Annuler", ButtonBar.ButtonData.CANCEL_CLOSE);

		Alert confirmAlert = new Alert(Alert.AlertType.CONFIRMATION, "", deleteButton, cancelButton);
		confirmAlert.setTitle("Confirmer la suppression");
		confirmAlert.setHeaderText("Supprimer l'evenement: " + safe(evenementToDelete.getTitre()) + " ?");
		confirmAlert.setContentText("Cette action est irreversible.");

		applyAlertTheme(confirmAlert);
		styleAlertButton(confirmAlert, cancelButton, "artist-secondary-button");
		styleAlertButton(confirmAlert, deleteButton, "artist-danger-button");

		Optional<ButtonType> result = confirmAlert.showAndWait();
		if (result.isEmpty() || result.get() != deleteButton) {
			return;
		}

		try {
			evenementService.deleteForArtiste(evenementToDelete, CURRENT_ARTIST_ID);
			refreshEvenements();
		} catch (SQLDataException e) {
			showError("Suppression impossible", e.getMessage());
		}
	}

	private Optional<Evenement> openFormDialog(Evenement evenementToEdit) {
		try {
			FXMLLoader loader = new FXMLLoader(Objects.requireNonNull(getClass().getResource("/views/artist/EvenementForm.fxml")));
			Parent formRoot = loader.load();
			EvenementArtisteFormController controller = loader.getController();

			Stage stage = new Stage();
			stage.initModality(Modality.APPLICATION_MODAL);
			if (addEvenementButton != null && addEvenementButton.getScene() != null) {
				stage.initOwner(addEvenementButton.getScene().getWindow());
			}
			stage.setTitle(evenementToEdit == null ? "Ajouter un evenement" : "Modifier un evenement");

			Scene scene = new Scene(formRoot);
			URL stylesheet = getClass().getResource("/views/styles/artist-theme.css");
			if (stylesheet != null) {
				scene.getStylesheets().add(stylesheet.toExternalForm());
			}
			stage.setScene(scene);

			controller.setDialogStage(stage);
			controller.setEvenement(evenementToEdit);

			stage.showAndWait();
			return Optional.ofNullable(controller.getResultEvenement());
		} catch (IOException e) {
			showError("Ouverture impossible", "Le formulaire evenement artiste est introuvable.");
			return Optional.empty();
		}
	}

	private void showError(String title, String message) {
		Alert alert = new Alert(Alert.AlertType.ERROR);
		alert.setTitle("Erreur");
		alert.setHeaderText(title);
		alert.setContentText(message);
		applyAlertTheme(alert);
		alert.showAndWait();
	}

	private void applyAlertTheme(Alert alert) {
		URL stylesheet = getClass().getResource("/views/styles/artist-theme.css");
		if (stylesheet != null) {
			alert.getDialogPane().getStylesheets().add(stylesheet.toExternalForm());
		}
		alert.getDialogPane().getStyleClass().add("artist-alert");
	}

	private void styleAlertButton(Alert alert, ButtonType buttonType, String styleClass) {
		Node node = alert.getDialogPane().lookupButton(buttonType);
		if (node instanceof Button button) {
			button.getStyleClass().add(styleClass);
			button.setMinWidth(110);
		}
	}

	private String safe(String value) {
		return value == null ? "" : value;
	}

	private boolean contains(String value, String search) {
		return value != null && value.toLowerCase().contains(search);
	}

	private static LocalDateTime safeDateTime(Evenement event) {
		return event.getDateDebut() == null ? LocalDateTime.MIN : event.getDateDebut();
	}
}

